const M = 17;
const tr = [[0, 0]];

function insert(x) {
    let u = 0;
    for (let i = M - 1; i >= 0; --i) {
        const v = (x >> i) & 1;
        if (!tr[u][v]) {
            const idx = tr.length;
            tr[u][v] = idx;
            tr.push([0, 0]);
        }
        u = tr[u][v];
    }
}

function query(x, y = 0) {
    let u = 0;
    let ans = 0;
    for (let i = M - 1; i >= 0; --i) {
        let v = ((x >> i) & 1) ^ 1;
        if (!tr[u][v]) v ^= 1;
        ans |= (y = (y << 1) | v);
        u = tr[u][v];
    }
    return ans;
}

function dfs(u, tree = 0, g = [], ans = []) {
    insert(tree ^= u);
    ans[u] = query(tree);
    for (const v of g[u]) {
        dfs(v, tree, g, ans);
    }
}

function maxGeneticDifference(parents, queries) {
    const n = parents.length;
    const edges = Array.from({length: n}, () => []);
    let root = -1;
    for (let i = 0; i < n; ++i) {
        if (parents[i] === -1) {
            root = i;
        } else {
            edges[parents[i]].push(i);
        }
    }

    const ans = Array(n).fill(0);
    dfs(root, 0, edges, ans);

    const result = queries.map(([node, val]) => ans[node] ^ val);
    return result;
}
