    ```java
import java.util.ArrayList;
import java.util.List;

public class Solution {
    private static final int M = 17;
    private final List<List<Integer>> tr = new ArrayList<>();

    public int[] maxGeneticDifference(int[] parents, int[][] queries) {
        int n = parents.length;
        List<List<Integer>> edges = new ArrayList<>(n);
        for (int i = 0; i < n; ++i) {
            edges.add(new ArrayList<>());
        }
        int root = -1;
        for (int i = 0; i < n; ++i) {
            if (parents[i] == -1) {
                root = i;
            } else {
                edges.get(parents[i]).add(i);
            }
        }

        tr.add(new ArrayList<>(2));
        tr.get(0).add(0);
        tr.get(0).add(0);
        int[] ans = new int[n];
        dfs(root, 0, edges, ans);

        int[] result = new int[queries.length];
        for (int i = 0; i < queries.length; ++i) {
            result[i] = ans[queries[i][0]] ^ queries[i][1];
        }
        return result;
    }

    private void insert(int x) {
        int u = 0;
        for (int i = M - 1; i >= 0; --i) {
            int v = (x >> i) & 1;
            if (tr.get(u).get(v) == 0) {
                tr.get(u).set(v, tr.size());
                List<Integer> newRow = new ArrayList<>(2);
                newRow.add(0);
                newRow.add(0);
                tr.add(newRow);
            }
            u = tr.get(u).get(v);
        }
    }

    private int query(int x, int y) {
        int u = 0, ans = 0;
        for (int i = M - 1; i >= 0; --i) {
            int v = ((x >> i) & 1) ^ 1;
            if (tr.get(u).get(v) == 0) v ^= 1;
            ans |= (y = (y << 1) | v);
            u = tr.get(u).get(v);
        }
        return ans;
    }

    private void dfs(int u, int tree, List<List<Integer>> g, int[] ans) {
        insert(tree ^= u);
        ans[u] = query(tree);
        for (int v : g.get(u)) {
            dfs(v, tree, g, ans);
        }
    }
}
```


